import { motion, AnimatePresence } from 'framer-motion';
import React, { useState, useEffect } from 'react';

const slides = [
    {
        title: "Hyderabad Morning Rush",
        stat: "142 Orders",
        img: "https://images.unsplash.com/photo-1572445271230-a78b5944a659?q=80&w=2000" // Charminar/City vibes
    },
    {
        title: "Delivery Efficiency",
        stat: "98% On-Time",
        img: "https://images.unsplash.com/photo-1586528116311-ad8dd3c8310d?q=80&w=2000" // Warehouse vibes
    }
];

const Highlights = () => {
    const [index, setIndex] = useState(0);

    useEffect(() => {
        const timer = setInterval(() => setIndex(prev => (prev + 1) % slides.length), 8000);
        return () => clearInterval(timer);
    }, []);

    return (
        <div style={{ width: '100%', height: '70vh', overflow: 'hidden', margin: '20px 0' }}>
            <AnimatePresence mode="wait">
                <motion.div
                    key={index}
                    initial={{ scale: 1.1, opacity: 0 }}
                    animate={{ scale: 1, opacity: 1 }}
                    exit={{ opacity: 0 }}
                    transition={{ duration: 2 }}
                    style={{
                        width: '100%', height: '100%',
                        backgroundImage: `linear-gradient(rgba(0,0,0,0.5), rgba(0,0,0,0.5)), url(${slides[index].img})`,
                        backgroundSize: 'cover', backgroundPosition: 'center',
                        display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center', color: 'white'
                    }}
                >
                    <motion.h1 initial={{ y: 20 }} animate={{ y: 0 }} style={{ fontSize: '5rem' }}>
                        {slides[index].stat}
                    </motion.h1>
                    <p style={{ fontSize: '1.5rem', letterSpacing: '2px' }}>{slides[index].title}</p>
                </motion.div>
            </AnimatePresence>
        </div>
    );
};

export default Highlights;
